// Refresh-queue priority branch (2026-05-28): prefers new /api/agent-handoffs shape,
// falls back to legacy HubSpot HANDOFF: marker for the 30-day transition.
const refreshResp = (() => { try { return $("Fetch Refresh Queue").first().json; } catch(e) { return null; }})();
const handoffRows = (refreshResp && refreshResp.handoffs) || [];
const refreshResults = (refreshResp && refreshResp.results) || [];

let refreshPick = null;
let refreshHandoffId = null;

// === NEW shape: typed REST handoff queue ===
for (const row of handoffRows) {
  if ((row.kind || "") !== "refresh_url") continue;
  const payload = row.payload || {};
  if (!payload.url) continue;
  refreshPick = {
    piece_type: "refresh",
    url: payload.url,
    title: payload.title || "(refresh) " + payload.url,
    click_drop_pct: payload.click_drop_pct,
    position_drop: payload.position_drop,
    source_ticket_id: row.source_ticket_id || null,
    source_agent: row.from_agent || "Content Decay Detector",
    target_keyword: payload.target_keyword || null,
    parent_anchor_url: payload.parent_anchor_url || null,
  };
  refreshHandoffId = row.id;
  break;
}

// === LEGACY fallback: HubSpot tickets w/ HANDOFF: marker in outcome_notes ===
if (!refreshPick) {
  for (const t of refreshResults) {
    const props = t.properties || {};
    const notes = props.outcome_notes || "";
    const idx = notes.indexOf("HANDOFF:");
    if (idx < 0) continue;
    const tail = notes.slice(idx + "HANDOFF:".length).trim();
    const start = tail.indexOf("{");
    if (start < 0) continue;
    let depth = 0, end = -1;
    for (let i = start; i < tail.length; i++) {
      const ch = tail[i];
      if (ch === "{") depth++;
      else if (ch === "}") { depth--; if (depth === 0) { end = i; break; } }
    }
    if (end < 0) continue;
    let handoff = null;
    try { handoff = JSON.parse(tail.slice(start, end + 1)); } catch(e) { continue; }
    if (!handoff || handoff.to !== "Owl") continue;
    const payload = handoff.payload || {};
    if (payload.kind !== "refresh_url" || !payload.url) continue;
    refreshPick = {
      piece_type: "refresh",
      url: payload.url,
      title: payload.title || props.subject || "(refresh) " + payload.url,
      click_drop_pct: payload.click_drop_pct,
      position_drop: payload.position_drop,
      source_ticket_id: t.id || props.id,
      source_agent: "Content Decay Detector",
      target_keyword: payload.target_keyword || null,
      parent_anchor_url: payload.parent_anchor_url || null,
    };
    break;
  }
}

if (refreshPick) {
  return [{json:{
    pick: refreshPick,
    refresh_mode: true,
    refresh_handoff_id: refreshHandoffId,
    total_candidates: 1,
    refresh_queue_count: handoffRows.length || refreshResults.length,
    note: refreshHandoffId
      ? "Picked refresh from /api/agent-handoffs row " + refreshHandoffId
      : "Picked refresh from legacy HubSpot HANDOFF marker (transition fallback).",
  }}];
}

