const ask = "Publish a new " + (pick.piece_type || 'piece') + " titled \"" + (pick.title || '') + "\" (" + wc + " words). " + (assets_needed.length ? assets_needed.length + " rich assets recommended (image/infographic/PDF)." : "No rich assets needed.");

const why = pick.piece_type === 'anchor'
  ? "This is anchor content - long-form piece that ranks for high-volume keywords and provides reciprocal links to cluster pages. " + (pick.note || '')
  : "This is a cluster page supporting parent anchor \"" + (pick.parent_anchor_title || '') + "\". It targets " + (pick.target_keyword || 'a related keyword') + ".";

const ifApprove = "I'll publish this draft to WordPress as a private page (status: draft). You'll get a preview link from WordPress. If structural checks failed (" + (failed.join(', ') || 'none') + "), they'll show in the WP admin notes - fix before going public." + (assets_needed.length ? " Rich assets get a separate Asset Review ticket for designer/Cowork to create." : "");

const ifReject = "I'll skip this piece for 30 days. Your rejection comment trains the Pick Next Piece logic - if you said \"already exists\" or \"off-strategy\", I won't re-propose similar.";

const content = "ASK\n" + ask + "\n\nWHY\n" + why + "\n\nIF YOU APPROVE\n" + ifApprove + "\n\nIF YOU REJECT\n" + ifReject + "\n\n--- DRAFT PREVIEW (first 1500 chars) ---\n" + draft.slice(0, 1500);

const recommendation_detail={
  pick,
  checks,
  failed,
  word_count: wc,
  draft_preview: (draft || '').slice(0, 8000),
  draft_full: draft,
  assets_needed,
  linkedin_derivatives: (linkedinRaw || '').slice(0, 3000)
};

const body_payload={
  properties:{
    subject: subject,
    content: content,
    hs_pipeline:"0",
    hs_pipeline_stage:"1",
    hs_ticket_priority: passed ? "MEDIUM" : "LOW",
    agent_name:"Content Producer",
    recommendation_type:"Content Draft",
    recommendation_detail:JSON.stringify(recommendation_detail)
  }
};
const body_str=JSON.stringify(body_payload);

return [{json:{passed,failed,checks,word_count:wc,draft,linkedin_raw:linkedinRaw,assets_needed,pick,subject,content,body_str}}];
